import StoreKit
class StoreKitManager: NSObject, SKProductsRequestDelegate, SKPaymentTransactionObserver { static let shared = StoreKitManager(); func requestProducts() { let request = SKProductsRequest(productIdentifiers: [\"com.jarvis.premium\"]); request.delegate = self; request.start() } func productsRequest(_ request: SKProductsRequest, didReceive response: SKProductsResponse) { if let product = response.products.first { let payment = SKPayment(product: product); SKPaymentQueue.default().add(payment) } } func paymentQueue(_ queue: SKPaymentQueue, updatedTransactions transactions: [SKPaymentTransaction]) { for transaction in transactions { if transaction.transactionState == .purchased { print(\"Premium Unlocked\"); queue.finishTransaction(transaction) } } } }
